INSERT INTO "inbox_queue" ("id","gmail_message_id","from_email","from_name","subject","body_preview","received_at","ai_from","ai_means","ai_team","ai_due_date","ai_remarks","status","inward_id","created_at","gmail_thread_id") VALUES(18,'19d43404eb3e3f5b','gpavanakumari@sssihl.edu.in','Dr. G Pavana Kumari, Dept. of Chemistry, SSSIHL','Request for CIE Marks Entry Link for Subhashree Priyadarshini',replace(replace('Dear Sir,\r\n  Sairam.\r\n  Ms. Subhashree Priyadarshini (Register No. 232214) is repeating the\r\nUCHM-402 course. I kindly request you to provide the link for entering her\r\nCIE marks.\r\n\r\nThank you.\r\n\r\nRegards,\r\n\r\nDr.G.Pavana Kumari\r\n\r\n-- \r\nDr. (Mrs) G. Pavana Kumari\r\nAssociate Professor\r\nDepartment of chemistry\r\nSSSIHL, Anantapur Campus\r\nAnantapur','\r',char(13)),'\n',char(10)),'2026-03-31T09:36:06.000Z','Dr. G Pavana Kumari, Dept. of Chemistry, SSSIHL','Email','','','','rejected',NULL,'2026-04-13 07:15:45',NULL);
INSERT INTO "inbox_queue" ("id","gmail_message_id","from_email","from_name","subject","body_preview","received_at","ai_from","ai_means","ai_team","ai_due_date","ai_remarks","status","inward_id","created_at","gmail_thread_id") VALUES(19,'19d431f502bede7a','controller@sssihl.edu.in','Controller of Examinations, SSSIHL','Re: Statement of Marks – CIE – MBAG-202: Research Methods for Managers.',replace(replace('*Dear Prof. Raja Sankaran*\r\n\r\n*Sairam!*\r\n\r\nGreetings from the Examinations Section, SSSIHL.\r\n\r\nYou may kindly enter the marks as mentioned in your email.\r\n\r\n*However, I would like to clarify 2 points here:*\r\n\r\n1. At SSSIHL, we use the labels SE and ST only for Practicals courses\r\n(which are typically of the ''I'' type). For Theory courses, of the ''I'' type,\r\nwe use the labels CIE-1, CIE-2, CIE-3 and so on and the final test is\r\ncalled a Summative Test. For Theory courses, of the ''IE'' type, we use the\r\nlabels CIE-1, CIE-2, CIE-3 and so on and the final test is the End Semester\r\nExamination (ESE).\r\n\r\n2. We do not permit upscaling or downscaling of marks. Therefore, please\r\nensure Assignments are evaluated for 70 marks and Summative Test is\r\nevaluated for 30 marks.\r\n\r\nThank you\r\n\r\nLoving Regards','\r',char(13)),'\n',char(10)),'2026-03-31T09:00:00.000Z','Controller of Examinations, SSSIHL','Email','','','','rejected',NULL,'2026-04-13 07:15:48',NULL);
INSERT INTO "inbox_queue" ("id","gmail_message_id","from_email","from_name","subject","body_preview","received_at","ai_from","ai_means","ai_team","ai_due_date","ai_remarks","status","inward_id","created_at","gmail_thread_id") VALUES(20,'19d42e2f56b02158','rajasankaran@sssihl.edu.in','Dr. Raja Sankaran, Dept. of Management & Commerce, SSSIHL','Re: Statement of Marks – CIE – MBAG-202: Research Methods for Managers.',replace(replace('Sairam Sir,\r\n\r\nSince I have given 4 assignments to the students followed by internal exam,\r\nI will be using SE & ST i.e. first 2 columns C1 and C2 in the statement of\r\nmarks.\r\n\r\nSE - out of 70 marks (for 4 assignments)\r\nST - out of 30 marks\r\n\r\nI have also discussed with our HoD in the afternoon today.\r\n\r\nRegards,\r\n\r\nDr. Raja Sankaran\r\n\r\n"*Education should be for life, not for a living.*"\r\n\r\n\r\n\r\nOn Tue, 31 Mar 2026 at 09:28, Dr. Raja Sankaran, Dept. of Management &\r\nCommerce, SSSIHL <rajasankaran@sssihl.edu.in> wrote:\r\n\r\n> Sure Sir,\r\n>\r\n> I will discuss with our HoD and will do the needful.\r\n>\r\n> Regards,\r\n>\r\n> Dr. Raja Sankaran\r\n>\r\n> "*Education should be for life, not for a living.*"\r\n>\r\n>\r\n>\r\n> On Tue, 31 Mar 2026 at 09:10, Controller of Examinations, SSSIHL <\r\n> controller@sssihl.edu.in','\r',char(13)),'\n',char(10)),'2026-03-31T07:54:07.000Z','Dr. Raja Sankaran, Dept. of Management & Commerce, SSSIHL','Email','','','','rejected',NULL,'2026-04-13 07:15:52',NULL);
