INSERT INTO "inbox_queue" ("id","gmail_message_id","from_email","from_name","subject","body_preview","received_at","ai_from","ai_means","ai_team","ai_due_date","ai_remarks","status","inward_id","created_at","gmail_thread_id") VALUES(24,'19d41faa5f6a8313','controller@sssihl.edu.in','Controller of Examinations, SSSIHL','Re: Statement of Marks – CIE – MBAG-202: Research Methods for Managers.',replace(replace('*Dear Prof. Raja Sankaran*\r\n\r\n*Sairam!*\r\n\r\nGreetings from the Examinations Section, SSSIHL.\r\n\r\nKindly refer to the Academic Regulations governing the MBA programme with\r\neffect from the batch that joined in July 2024 and onwards.\r\n\r\nRegulation-6, Table-2 states that for ''I'' type Theory courses with 100\r\nmarks (3 credits or more), we need to conduct Tests, Seminars and\r\nAssignments (CIE) for 70 marks and Summative Evaluation for 30 marks, such\r\nthat it totals to 100 marks\r\n\r\nWe request you to kindly comply with the above requirement and then enter\r\nthe marks in the marks statement as follows:\r\n\r\nCiE - Assignment 1 - C1\r\nCIE - Assignment 2 - C2\r\nCIE - Assignment 3 - C3\r\nSummative Evaluation - C4\r\n\r\nThank you\r\n\r\nLoving Regards\r\n\r\nDr. G S Srirangarajan\r\nController of Examinations\r\nSri Sathya S','\r',char(13)),'\n',char(10)),'2026-03-31T03:40:20.000Z','Controller of Examinations, SSSIHL','Email','','','','rejected',NULL,'2026-04-13 07:16:08',NULL);
