INSERT INTO "inbox_queue" ("id","gmail_message_id","from_email","from_name","subject","body_preview","received_at","ai_from","ai_means","ai_team","ai_due_date","ai_remarks","status","inward_id","created_at","gmail_thread_id") VALUES(104,'19d8a3fa759c9119','dycontroller@sssihl.edu.in','Deputy Controller of Examinations, SSSIHL','Re: CIE Clearance Sign off by students for results processing',replace(replace('Dear Ma''m\r\n\r\nI have interleaved responses into your email.\r\n\r\nRegards,\r\n\r\nOn Tue, Apr 14, 2026 at 9:24â¯AM Director, ATP Campus, SSSIHL <\r\ndirectoratp@sssihl.edu.in> wrote:\r\n\r\n> Thank you, for the clarification, Sir.\r\n>\r\n> So:\r\n> Students can sign off only after all faculty feed all marks?\r\n> If yes, a note to all faculty to expedite marks entry will be good. We\r\n> have done that at campus level.\r\n>\r\nYes, they can sign off only when all marks are available. A please-expedite\r\nauto reminder is scheduled to go in a day or two. Thereafter, our daily\r\nreminders will keep the heat on.\r\n\r\n\r\n> What happens to Swayam courses, the results of which will come later?\r\n>\r\nWhere SWAYAM courses cause a delay, we are forced to allow students to give\r\nclearance when the SWAYAM results come.\r\n\r\nCan student','\r',char(13)),'\n',char(10)),'2026-04-14T04:28:19.000Z','Deputy Controller of Examinations, SSSIHL','Email','','','','pending',NULL,'2026-04-14 10:30:45','19d863bd73900b9d');
