INSERT INTO "inbox_queue" ("id","gmail_message_id","from_email","from_name","subject","body_preview","received_at","ai_from","ai_means","ai_team","ai_due_date","ai_remarks","status","inward_id","created_at","gmail_thread_id") VALUES(110,'19d89c52d12257cb','dycontroller@sssihl.edu.in','Deputy Controller of Examinations, SSSIHL','Re: CIE Clearance Sign off by students for results processing',replace(replace('Dear Madam\r\n\r\nIn conformance with the present chain of information flows in CIEs, we\r\nrequest Campus Directors only to share the webapp link with students and\r\ninstruct them to act on it. Students must be told that confirmation of\r\nclearance for results processing is a prerequisite to results processing. A\r\nlive, identity masked sample image of what students will see is below. Note\r\nthat the confirm button will be seen below the blue text box when the marks\r\nof all courses are released by respective teachers.\r\n\r\nStudents must use the email addresses registered with us as (submitted by\r\ncampuses in response to the email from the COE dated 15-Sep-2025, subject\r\n"Request to share email ids of all the students in your Campus"). In the\r\nsecond email shared with you yesterday, subject "Tracking','\r',char(13)),'\n',char(10)),'2026-04-14T02:14:37.000Z','Deputy Controller of Examinations, SSSIHL','Email','','','','pending',NULL,'2026-04-14 10:30:52','19d863bd73900b9d');
