INSERT INTO "inbox_queue" ("id","gmail_message_id","from_email","from_name","subject","body_preview","received_at","ai_from","ai_means","ai_team","ai_due_date","ai_remarks","status","inward_id","created_at","gmail_thread_id") VALUES(112,'19d8796187f06396','directoratp@sssihl.edu.in','Director, ATP Campus, SSSIHL','Re: CIE Clearance Sign off by students for results processing',replace(replace('Dear Sir,\r\nSairam. Thank you for all the wonderful initiatives.\r\nWould like to know if the students have received any mail/ alert to do\r\nthis.\r\nIf yes, when was it sent, and what could be the contents of it.\r\nBefore we announce to students, it is good for us to know their side of it\r\nto answer any questions.\r\n\r\n\r\nWith warm regards,\r\nRani\r\n\r\nProf. Rani P. L.\r\nDirector\r\nSri Sathya Sai Institute of Higher Learning\r\nAnantapur Campus for Women\r\nAnantapur - 515001\r\nPh: 8331034770\r\n\r\n\r\nOn Mon, Apr 13, 2026 at 3:16â¯PM Deputy Controller of Examinations, SSSIHL <\r\ndycontroller@sssihl.edu.in> wrote:\r\n\r\n>\r\n>\r\n> Respected Directors\r\n>\r\n> SaiRam!\r\n>\r\n> This is regarding CIE Marks Statements. As you are aware, course teachers\r\n> certify CIE marks statements after students verify their component-wise\r\n>','\r',char(13)),'\n',char(10)),'2026-04-13T16:03:48.000Z','Director, ATP Campus, SSSIHL','Email','','','','pending',NULL,'2026-04-14 10:30:54','19d863bd73900b9d');
