INSERT INTO "inbox_queue" ("id","gmail_message_id","from_email","from_name","subject","body_preview","received_at","ai_from","ai_means","ai_team","ai_due_date","ai_remarks","status","inward_id","created_at","gmail_thread_id") VALUES(115,'19d863bd73900b9d','dycontroller@sssihl.edu.in','Deputy Controller of Examinations, SSSIHL','CIE Clearance Sign off by students for results processing',replace(replace('Respected Directors\r\n\r\nSaiRam!\r\n\r\nThis is regarding CIE Marks Statements. As you are aware, course teachers\r\ncertify CIE marks statements after students verify their component-wise\r\nscores.\r\n\r\nWe have introduced a step requiring students to give clearance that their\r\nCIE Marks may be taken up for results processing. Directors are requested\r\nto get announcements made on at least two occasions to ensure that students\r\nare informed about this mandatory requirement. The following may be kindly\r\nnoted in this regard and conveyed to students\r\n\r\n   - They must give clearance only via the webApp link.\r\n   - They must do it before leaving the campus for vacation/ internship.\r\n   - They may be informed that no requests for extension will be\r\n   entertained thereafter.\r\n\r\n\r\nLink for students to give','\r',char(13)),'\n',char(10)),'2026-04-13T09:45:42.000Z','Deputy Controller of Examinations, SSSIHL','Email','','','','pending',NULL,'2026-04-14 10:30:56','19d863bd73900b9d');
