PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE inward (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    inward_no TEXT UNIQUE NOT NULL,
    means TEXT,
    particulars_from_whom TEXT,
    subject TEXT,
    sign_receipt_datetime TEXT,
    file_reference TEXT,
    assigned_team TEXT,
    assigned_to_email TEXT,
    assignment_instructions TEXT,
    assignment_date TEXT,
    assignment_status TEXT DEFAULT 'Unassigned',
    due_date TEXT,
    completion_date TEXT,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT DEFAULT CURRENT_TIMESTAMP
, remarks TEXT);
CREATE TABLE outward (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    outward_no TEXT UNIQUE NOT NULL,
    means TEXT,
    to_whom TEXT,
    subject TEXT,
    sent_by TEXT,
    sign_receipt_datetime TEXT,
    case_closed INTEGER DEFAULT 0,
    file_reference TEXT,
    postal_tariff REAL,
    due_date TEXT,
    linked_inward_id INTEGER,
    created_by_team TEXT,
    team_member_email TEXT,
    remarks TEXT,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (linked_inward_id) REFERENCES inward(id)
);
CREATE TABLE notes (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    note_type   TEXT NOT NULL,
    sl_no       TEXT NOT NULL,
    outward_no  TEXT NOT NULL,
    date        TEXT NOT NULL,
    description TEXT NOT NULL,
    remarks     TEXT,
    created_at  TEXT DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE audit_log (id INTEGER PRIMARY KEY AUTOINCREMENT, action TEXT NOT NULL, actor TEXT NOT NULL, description TEXT NOT NULL, inward_no TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE push_subscriptions (id INTEGER PRIMARY KEY AUTOINCREMENT, endpoint TEXT UNIQUE NOT NULL, p256dh TEXT NOT NULL, auth TEXT NOT NULL, team TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE inbox_queue (
                id               INTEGER PRIMARY KEY AUTOINCREMENT,
                gmail_message_id TEXT UNIQUE NOT NULL,
                from_email       TEXT NOT NULL,
                from_name        TEXT,
                subject          TEXT NOT NULL,
                body_preview     TEXT,
                received_at      TEXT NOT NULL,
                ai_from          TEXT,
                ai_means         TEXT DEFAULT 'Email',
                ai_team          TEXT,
                ai_due_date      TEXT,
                ai_remarks       TEXT,
                status           TEXT DEFAULT 'pending',
                inward_id        INTEGER,
                created_at       TEXT DEFAULT CURRENT_TIMESTAMP
            , gmail_thread_id TEXT);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_inward_status ON inward(assignment_status);
CREATE INDEX idx_inward_assigned_team ON inward(assigned_team);
CREATE INDEX idx_outward_created_by_team ON outward(created_by_team);
CREATE INDEX idx_notes_type ON notes(note_type);
CREATE INDEX idx_audit_log_created ON audit_log(created_at);
CREATE INDEX idx_inbox_queue_status ON inbox_queue(status);
